final:
module RefModule (
    input wire [3:0] D,
    input wire Clk,
    input wire Shift,
    output reg [3:0] Q
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt) begin
    if (Shift)
        Q <= {1'b0, Q[3:1]};
    else
        Q <= D;
end

endmodule
